    def nonce(self):
        return self.milliseconds() - self.options['timeDifference']

    async def fetch_time(self, params={}):
        return self.milliseconds()

    async def load_time_difference(self, params={}):
        serverTime = await self.fetch_time(params)
        after = self.milliseconds()
        self.options['timeDifference'] = after - serverTime
        return self.options['timeDifference']

    def sign(self, path, api='public', method='GET', params={}, headers=None, body=None):
        if not (api in self.urls['api']):
            raise NotSupported(self.id + ' does not have a testnet/sandbox URL for ' + api + ' endpoints')
        request = '/' + self.implode_params(path, params)
        query = self.omit(params, self.extract_params(path))
        if method == 'GET':
            if query:
                request += '?' + self.urlencode(query)
        if api == 'private':
            if params['limit'] is not None:
                request += '?' + self.urlencode({'limit': params['limit'], 'page': params['page']})
                del params['limit']
                del params['page']
            self.check_required_credentials()
            nonce = int(self.nonce() / 1000)
            params = self.extend({'timestamp': nonce, 'recvWindow': 5000}, params)
            hmac = self.get_hmac_from_object(params)
            body = self.json(params)
            headers = {
                'apiKey': self.apiKey,
                'HMAC': hmac,
                'Content-Type': 'application/json',
            }
        url = self.urls['api'][api] + request
        return {'url': url, 'method': method, 'body': body, 'headers': headers}

    async def fetch_balance(self, params={}):
        currency = self.safe_string(params, 'currency')
        if currency is None:
            currency = 'ALL'
        else:
            currency = self.currency_id(currency)
        params['currency'] = currency
        response = await self.privatePostGetBalance(params)
        balances = self.safe_value(response, 'data', {})
        result = {'info': balances}
        for i in range(0, len(balances)):
            currencyId = self.safe_string(balances[i], 'currency')
            code = self.safe_currency_code(currencyId)
            account = self.account()
            free = self.safe_float(balances[i], 'balance')
            used = self.safe_float(balances[i], 'balanceInTrade')
            total = free + used
            account['total'] = total
            account['free'] = free
            account['used'] = used
            result[code] = account
        return self.parse_balance(result)

    async def create_order(self, symbol, type, side, amount, price=None, params={}):
        await self.load_markets()
        market = self.market(symbol)
        exchangeType = type.upper()
        exchangeSide = side.upper()
        baseId = market['id'].split('_')[1]
        quoteId = market['id'].split('_')[0]
        request = {
            'market': quoteId,
            'trade': baseId,
            'side': exchangeSide,
            'type': exchangeType,  # MARKET, LIMIT, STOPLIMIT
            'volume': self.amount_to_precision(symbol, amount),
        }
        if exchangeType == 'LIMIT':
            if price is None:
                raise InvalidOrder(self.id + ' createOrder method requires a price argument for a ' + type + ' order')
            request['rate'] = self.price_to_precision(symbol, price)
            timeInForce = self.safe_string(params, 'timeInForce')
            if timeInForce is not None:
                if timeInForce != 'GTC' and timeInForce != 'IOC' and timeInForce != 'FOK':
                    request['timeInForce'] = timeInForce
        if exchangeType == 'STOPLIMIT':
            stopPrice = self.safe_float(params, 'stopPrice')
            if price is None:
                raise InvalidOrder(self.id + ' createOrder method requires a price argument for a ' + type + ' order')
            if stopPrice is None:
                raise InvalidOrder(self.id + ' createOrder method requires a stop argument for a ' + type + ' order')
            request['rate'] = self.price_to_precision(symbol, price)
            request['stop'] = self.price_to_precision(symbol, stopPrice)
        if exchangeType == 'STOPMARKET':
            stopPrice = self.safe_float(params, 'stopPrice')
            if stopPrice is None:
                raise InvalidOrder(self.id + ' createOrder method requires a stop argument for a ' + type + ' order')
            request['stop'] = self.price_to_precision(symbol, stopPrice)
            request['timeInForce'] = 'GTC'
        if exchangeType == 'MARKET':
            if price is not None:
                raise InvalidOrder(self.id + ' createOrder method does not support price argument for a ' + type + ' order')
        response = await self.privatePostPlaceOrder(request)
        #
        #     {
        #         status: 'Success',
        #         data: {
        #             "orderId": 214083724
        #         }
        #    }
        #
        timestamp = self.seconds()
        result = self.safe_value(response, 'data')
        id = self.safe_integer(result, 'orderId')
        order = {
            'id': id,
            'info': response,
            'timestamp': timestamp,
            'datetime': self.iso8601(timestamp),
            'symbol': symbol,
            'type': type,
            'side': side,
            'price': price,
            'amount': amount,
            'cost': None,
            'average': None,
            'filled': None,
            'remaining': None,
            'status': None,
            'fee': None,
            'trades': None,
        }
        return order

