    async def fetch_markets(self, params={}):
        response = await self.publicGetApiGetSettings()
        if self.options['adjustForTimeDifference']:
            await self.load_time_difference()
        data = self.safe_value(response, 'data')
        res = self.safe_value(data, 'trade_setting')
        result = []
        for i in range(0, len(res)):
            market = res[i]
            baseId = self.safe_string(market, 'coinName')
            quoteId = self.safe_string(market, 'marketName')
            id = quoteId + '_' + baseId
            base = self.safe_currency_code(baseId)
            quote = self.safe_currency_code(quoteId)
            symbol = base + '/' + quote
            active = self.safe_value(market, 'tradeEnabled')
            taker = self.safe_float(market, 'takerFee')
            maker = self.safe_float(market, 'makerFee')
            lotSize = self.safe_float(market, 'minTradeAmount')
            tickSize = self.safe_float(market, 'minTickSize')
            minCost = self.safe_float(market, 'minOrderValue')
            # TODO: precision
            result.append({
                'id': id,
                'symbol': symbol,
                'base': base,
                'quote': quote,
                'active': active,
                'precision': {
                    'amount': lotSize,
                    'price': tickSize,
                },
                'taker': taker,
                'maker': maker,
                'limits': {
                    'amount': {
                        'min': None,
                        'max': None,
                    },
                    'price': {
                        'min': None,
                        'max': None,
                    },
                    'cost': {
                        'min': minCost,
                        'max': None,
                    },
                },
                'info': market,
            })
        return result

