    async def fetch_currencies(self, params={}):
        response = await self.publicGetApiCurrencySettings(params)
        currencies = self.safe_value(response, 'data')
        result = {}
        for i in range(0, len(currencies)):
            id = self.safe_string(currencies[i], 'shortName')
            # fees can have both percentage and flat fee
            code = self.safe_currency_code(id)
            name = self.safe_string(currencies[i], 'fullName')
            decimal = self.safe_integer(currencies[i], 'decimalPrecision')
            precision = math.pow(10, -decimal)
            # is active only if all of the below are True
            buyEnabled = self.safe_value(currencies[i], 'tradeEnabled_Buy')
            sellEnabled = self.safe_value(currencies[i], 'tradeEnabled_Sell')
            depositEnabled = self.safe_value(currencies[i], 'depositEnabled')
            withdrawalEnabled = self.safe_value(currencies[i], 'withdrawalEnabled')
            feeType = self.safe_string(currencies[i], 'withdrawalServiceChargeType')
            flatFee = self.safe_float(currencies[i], 'withdrawalServiceCharge')
            feePercentage = self.safe_float(currencies[i], 'withdrawalServiceChargeInBTC')
            if feeType == 'Percentage':
                if feePercentage == 0:
                    feePercentage = self.safe_float(currencies[i], 'withdrawalServiceCharge')
                    flatFee = 0
                else:
                    feeType = 'Mixed'
            active = buyEnabled and sellEnabled and depositEnabled and withdrawalEnabled
            result[code] = {
                'id': id,
                'code': code,
                'name': name,
                'active': active,
                # Warning: fee can be both percentage and flat. The `fee` field will have the flat one
                'fee': flatFee,
                'precision': precision,
                'limits': {
                    'amount': {
                        'min': None,
                        'max': None,
                    },
                    'price': {
                        'min': None,
                        'max': None,
                    },
                    'cost': {
                        'min': None,
                        'max': None,
                    },
                    'withdraw': {
                        'min': None,
                        'max': None,
                    },
                },
                'info': currencies[i],
                # custom
                'buyEnabled': buyEnabled,
                'sellEnabled': sellEnabled,
                'depositEnabled': depositEnabled,
                'withdrawalEnabled': withdrawalEnabled,
                'feeType': feeType,  # Fixed | Percentage | Mixed
                'feePercentage': feePercentage,
            }
        return result

