    async def fetch_trades(self, symbol, limit=None, params={}):
        await self.load_markets()
        market = self.market(symbol)
        id = market['id']
        request = {
            'pair': id,
        }
        # WARNING: pagination not implemented yet. TODO
        response = await self.publicGetMarketGetTradeHistoryPair(self.extend(request, params))
        result = response['data']
        length = len(result)
        if length <= 0:
            return []
        normalizedTrades = []
        for i in range(0, len(result)):
            normalizedTrades.append(self.normalize_trade_object(result[i], market))
        return self.parse_trades(normalizedTrades, market)

    async def fetch_ohlcv(self, symbol, timeframe='1m', since=None, limit=100, params={}):
        await self.load_markets()
        market = self.market(symbol)
        pair = market['id']
        quote = pair.split('_')[0]
        base = pair.split('_')[1]
        minutes = self.timeframes[timeframe]
        if minutes is None:
            minutes = 1
        oldSince = since
        if since is None:
            since = self.milliseconds()
        else:
            # recalculate the timestamp. The exchange expects the `until' timestamp instead of since
            since = since + (limit * (minutes * (60 * 1000)))
        request = {
            'baseCurrency': base,
            'quoteCurrency': quote,
            'interval': minutes,
            'timestamp': since,
            'limit': limit,
        }
        response = await self.publicGetMarketGetChartData(self.extend(request, params))
        result = self.safe_value(response, 'data', {})
        # revert since to avoid the check in parseOHLCVs where candles outside the timestamp are removed
        since = oldSince
        return self.parse_ohlcvs(result, market, timeframe, since, limit)

