    def normalize_order_object(self, order):
        return {
            'orderId': order['OrderId'],
            'market': order['Market'],
            'trade': order['Trade'],
            'volume': order['Volume'],
            'pendingVolume': order['PendingVolume'],
            'orderStatus': order['Status'],
            'rate': order['Price'],
            'placementDate': order['PlacementDate'],
            'completionDate': order['CompletionDate'],
            'side': order['Side'],
            'type': order['Type'],
        }

    def parse_order(self, order, market=None):
        side = self.safe_string(order, 'side')
        if side is not None:
            side = side.lower()
        type = self.safe_string(order, 'type')
        if type is not None:
            type = type.lower()
        marketCurrency = self.safe_string(order, 'market')
        tradeCurrency = self.safe_string(order, 'trade')
        marketId = marketCurrency + '_' + tradeCurrency
        market = self.markets_by_id[marketId]
        orderStatus = self.safe_value(order, 'orderStatus')
        dateTime = None
        if orderStatus:
            # closed order
            dateTime = self.safe_string(order, 'completionDate')
        else:
            # open order
            dateTime = self.safe_string(order, 'placementDate')
        timestamp = self.parse8601(dateTime)
        amount = self.safe_float(order, 'volume')
        remaining = self.safe_float(order, 'pendingVolume')
        filled = amount - remaining
        price = self.safe_float(order, 'rate')
        cost = price * filled
        symbol = None
        if market is not None:
            symbol = market['symbol']
        status = self.parse_order_status(orderStatus, filled)
        rawTrades = self.safe_value(order, 'mOrders')
        averagePrice = 0
        fee = 0
        trades = []
        if rawTrades is not None and len(rawTrades) != 0:
            for i in range(0, len(rawTrades)):
                tradePrice = self.safe_float(rawTrades[i], 'rate')
                averagePrice += tradePrice
                tradeFee = self.safe_float(rawTrades[i], 'serviceCharge')
                fee += tradeFee
                trades.append(self.parse_trade(rawTrades[i]))
            averagePrice = averagePrice / len(trades)
        id = self.safe_value(order, 'orderId')
        return {
            'id': id,
            'clientOrderId': None,
            'info': order,
            'timestamp': timestamp,
            'datetime': dateTime,
            'lastTradeTimestamp': None,
            'status': status,
            'symbol': symbol,
            'type': type,
            'side': side,
            'price': price,
            'cost': cost,
            'amount': amount,
            'filled': filled,
            'average': averagePrice,
            'remaining': remaining,
            'fee': fee,
            'trades': trades,
        }

    def parse_order_status(self, status, filled):
        orderStatus = None
        if not status:
            orderStatus = 'open'
        elif filled == 0:
            orderStatus = 'canceled'
        else:
            orderStatus = 'closed'
        return orderStatus

    def parse_ohlcv(self, ohlcv, market=None):
        return [
            self.safe_integer(ohlcv, 'time'),
            self.safe_float(ohlcv, 'open'),
            self.safe_float(ohlcv, 'high'),
            self.safe_float(ohlcv, 'low'),
            self.safe_float(ohlcv, 'close'),
            self.safe_float(ohlcv, 'volume'),
        ]

    def normalize_trade_object(self, trade, market=None):
        id = self.safe_value(trade, 'TradeID')
        rate = self.safe_float(trade, 'Rate')
        volume = self.safe_float(trade, 'Volume')
        cost = self.safe_float(trade, 'Total')
        side = self.safe_string(trade, 'Type')
        date = self.safe_string(trade, 'Date')
        s = market['id'].split('_')
        base = s[1]
        quote = s[0]
        return {
            'orderId': str(id),
            'volume': volume,
            'rate': rate,
            'trade': base,
            'market': quote,
            'amount': cost,
            'serviceCharge': None,
            'date': date,
            'side': side.upper(),
        }

    def parse_trade(self, trade, market=None):
        id = self.safe_value(trade, 'orderId')
        rate = self.safe_float(trade, 'rate')
        volume = self.safe_float(trade, 'volume')
        cost = self.safe_float(trade, 'amount')
        side = self.safe_string(trade, 'side')
        date = self.safe_string(trade, 'date')
        fee = self.safe_float(trade, 'serviceCharge')
        baseId = self.safe_string(trade, 'trade')
        quoteId = self.safe_string(trade, 'market')
        marketId = quoteId + '_' + baseId
        symbol = self.markets_by_id[marketId]['symbol']
        timestamp = self.parse8601(date)
        return {
            'id': None,
            'order': id,
            'info': trade,
            'timestamp': timestamp,
            'datetime': self.iso8601(timestamp),
            'symbol': symbol,
            'type': None,
            'side': side.lower(),
            'takerOrMaker': None,
            'price': rate,
            'amount': volume,
            'cost': cost,
            'fee': fee,
        }

    def parse_tickers(self, rawTickers, market=None):
        tickers = {}
        pairs = list(rawTickers.keys())
        for i in range(0, len(pairs)):
            symbol = self.safe_symbol(pairs[i])
            tickers[symbol] = self.parse_ticker(rawTickers[pairs[i]], pairs[i])
        return tickers

    def parse_ticker(self, ticker, marketId=None):
        timestamp = self.milliseconds()
        symbol = self.safe_symbol(marketId)
        last = self.safe_float(ticker, 'Last')
        return {
            'symbol': symbol,
            'timestamp': timestamp,
            'datetime': self.iso8601(timestamp),
            'high': self.safe_float(ticker, 'High_24hr'),
            'low': self.safe_float(ticker, 'Low_24hr'),
            'bid': self.safe_float(ticker, 'HeighestBid'),
            'bidVolume': None,
            'ask': self.safe_float(ticker, 'LowestAsk'),
            'askVolume': None,
            'vwap': self.safe_float(ticker, 'weightedAvgPrice'),
            'open': self.safe_float(ticker, 'openPrice'),
            'close': last,
            'last': last,
            'previousClose': None,
            'change': None,
            'percentage': self.safe_float(ticker, 'PercentChange'),
            'average': None,
            'baseVolume': self.safe_float(ticker, 'QuoteVolume'),
            'quoteVolume': self.safe_float(ticker, 'BaseVolume'),
            'info': ticker,
        }

    def get_hmac_from_object(self, data):
        queryString = ''
        keys = list(data.keys())
        keys.sort()
        for i in range(0, len(keys)):
            queryString += keys[i] + '=' + data[keys[i]]
            if i < len(keys) - 1:
                queryString += '&'
        hmac = self.hmac(queryString, self.secret, hashlib.sha512, 'hex')
        hmacString = hmac.upper()
        return hmacString
